import{_ as t,c as s,o as n,a1 as e}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"上下文优化：节省 Token 的分会话执行 | Agent App Factory 教程","description":"学习如何使用 factory continue 命令节省 Token，在每个阶段新建会话。通过分会话执行，每个阶段独享干净上下文，大幅降低使用成本。本教程涵盖上下文隔离策略、状态恢复机制和最佳实践，帮助你掌握 Token 优化技巧。","frontmatter":{"title":"上下文优化：节省 Token 的分会话执行 | Agent App Factory 教程","sidebarTitle":"上下文优化","subtitle":"上下文优化：分会话执行","description":"学习如何使用 factory continue 命令节省 Token，在每个阶段新建会话。通过分会话执行，每个阶段独享干净上下文，大幅降低使用成本。本教程涵盖上下文隔离策略、状态恢复机制和最佳实践，帮助你掌握 Token 优化技巧。","tags":["进阶","性能优化","Token 节省"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":160},"headers":[],"relativePath":"zh/hyz1992/agent-app-factory/advanced/context-optimization/index.md","filePath":"zh/hyz1992/agent-app-factory/advanced/context-optimization/index.md"}'),i={name:"zh/hyz1992/agent-app-factory/advanced/context-optimization/index.md"};function o(l,a,p,r,c,d){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="上下文优化-分会话执行" tabindex="-1">上下文优化：分会话执行 <a class="header-anchor" href="#上下文优化-分会话执行" aria-label="Permalink to &quot;上下文优化：分会话执行&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>使用 <code>factory continue</code> 命令在新会话中继续流水线</li><li>理解每个阶段独享干净上下文的优势</li><li>掌握大幅降低 Token 消耗的方法</li><li>支持中断恢复，随时暂停和继续</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>当你在 AI 助手（如 Claude Code）中执行完整的 7 阶段流水线时，可能会遇到这些问题：</p><ul><li><strong>Token 越用越多</strong>：随着对话累积，上下文越来越长，每个阶段都要加载之前所有阶段的内容</li><li><strong>成本越来越高</strong>：长对话意味着更多的输入 Token，费用直线上升</li><li><strong>响应变慢</strong>：上下文过长可能导致响应时间增加</li><li><strong>难以恢复</strong>：如果某个阶段失败，重新开始需要重新加载大量上下文</li></ul><div class="tip custom-block"><p class="custom-block-title">核心问题</p><p>长对话的上下文累积是 AI 助手的固有特性，但我们可以通过&quot;分会话执行&quot;来规避这个问题。</p></div><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>是否使用分会话</th><th>原因</th></tr></thead><tbody><tr><td>完整执行 7 阶段流水线</td><td>✅ 强烈推荐</td><td>每个 Token 都很宝贵</td></tr><tr><td>仅执行 1-2 个阶段</td><td>⚠️ 可选</td><td>上下文较短，不一定需要</td></tr><tr><td>调试某个阶段</td><td>⚠️ 可选</td><td>频繁重试可能增加会话切换成本</td></tr><tr><td>长时间中断后恢复</td><td>✅ 必须使用</td><td>避免加载过时的上下文</td></tr></tbody></table><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Agent App Factory 支持<strong>分会话执行</strong>，其核心思想是：</p><p><strong>每个阶段结束后，用新会话执行下一个阶段。</strong></p><p>这样做的好处：</p><ol><li><strong>干净上下文</strong>：每个阶段只加载必要的输入文件，不依赖对话历史</li><li><strong>节省 Token</strong>：避免了将之前所有阶段的内容重复传递给 AI</li><li><strong>可恢复性</strong>：随时可以中断，之后用新会话继续，不会丢失进度</li><li><strong>跨平台兼容</strong>：适用于所有 AI 助手（Claude Code、OpenCode、Cursor 等）</li></ol><h3 id="上下文隔离策略" tabindex="-1">上下文隔离策略 <a class="header-anchor" href="#上下文隔离策略" aria-label="Permalink to &quot;上下文隔离策略&quot;">​</a></h3><p>为了实现分会话执行，Agent App Factory 采用了<strong>上下文隔离策略</strong>：</p><div class="info custom-block"><p class="custom-block-title">什么是上下文隔离？</p><p>上下文隔离是指每个 Agent 只依赖文件输入，不依赖对话历史。即使之前发生了什么，Agent 也只从指定的输入文件读取信息。</p></div><p>每个 Agent 执行时：</p><ul><li>✅ <strong>只读取</strong> <code>pipeline.yaml</code> 中定义的 <code>inputs</code> 文件</li><li>❌ <strong>不使用</strong> 对话历史中的任何&quot;记忆&quot;</li><li>❌ <strong>不假设</strong> 自己知道之前阶段发生了什么</li></ul><p>例如，Tech Agent 执行时：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Tech Agent] --&gt; B[读取 artifacts/prd/prd.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[生成 artifacts/tech/tech.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[更新 .factory/state.json]</span></span></code></pre></div><p>Tech Agent 只关心 <code>artifacts/prd/prd.md</code>，不会去想&quot;用户之前说想做什么应用&quot;，所有信息都来自输入文件。</p><h3 id="状态恢复机制" tabindex="-1">状态恢复机制 <a class="header-anchor" href="#状态恢复机制" aria-label="Permalink to &quot;状态恢复机制&quot;">​</a></h3><p>当你执行 <code>factory continue</code> 时，系统会：</p><ol><li>读取 <code>.factory/state.json</code> 获取当前进度</li><li>读取 <code>.factory/pipeline.yaml</code> 确定下一个阶段</li><li><strong>仅加载该阶段所需的输入文件</strong></li><li>启动新的 AI 助手窗口继续执行</li></ol><p>状态文件（<code>.factory/state.json</code>）是整个系统的&quot;记忆中心&quot;：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;waiting_for_confirmation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_stage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tech&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completed_stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bootstrap&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T12:00:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>每个阶段完成后，状态都会更新到这个文件中。新会话启动时，只要读取这个文件就能知道当前在哪里。</p><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置检查</p><p>在开始本教程前，请确保：</p><ul><li>[ ] 已完成 <a href="./../../start/getting-started/">快速开始</a> 并初始化了一个 Factory 项目</li><li>[ ] 已了解 <a href="./../../start/pipeline-overview/">7 阶段流水线概览</a></li><li>[ ] 已安装 Claude Code（或其他 AI 助手）</li></ul><p>如果还未完成，请先完成这些前置课程。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><p>让我们通过一个实际场景来学习如何使用 <code>factory continue</code> 命令。</p><h3 id="场景设定" tabindex="-1">场景设定 <a class="header-anchor" href="#场景设定" aria-label="Permalink to &quot;场景设定&quot;">​</a></h3><p>假设你正在执行一个 7 阶段流水线，目前已经完成了 <code>bootstrap</code> 和 <code>prd</code> 阶段，正在 <code>ui</code> 阶段等待确认。</p><h3 id="第-1-步-在检查点选择-新建会话继续" tabindex="-1">第 1 步：在检查点选择&quot;新建会话继续&quot; <a class="header-anchor" href="#第-1-步-在检查点选择-新建会话继续" aria-label="Permalink to &quot;第 1 步：在检查点选择&quot;新建会话继续&quot;&quot;">​</a></h3><p>当某个阶段完成后，Sisyphus 调度器会显示一个选项表格：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ ui 完成！</span></span>
<span class="line"><span></span></span>
<span class="line"><span>生成的产物：</span></span>
<span class="line"><span>- artifacts/ui/ui.schema.yaml</span></span>
<span class="line"><span>- artifacts/ui/preview.web/index.html</span></span>
<span class="line"><span>- artifacts/ui/preview.web/styles.css</span></span>
<span class="line"><span>- artifacts/ui/preview.web/app.js</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  📋 请选择下一步操作                                         │</span></span>
<span class="line"><span>│  输入选项数字（1-5），然后按回车键确认                        │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────┬──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 选项 │ 说明                                                  │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1   │ 继续下一阶段（同一会话）                               │</span></span>
<span class="line"><span>│      │ 我将继续执行 tech 阶段                                 │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2   │ 新建会话继续 ⭐ 推荐选项，节省 Token                   │</span></span>
<span class="line"><span>│      │ 在新的命令行窗口中执行：factory continue               │</span></span>
<span class="line"><span>│      │ （会自动启动新的 Claude Code 窗口并继续流水线）        │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3   │ 重跑该阶段                                             │</span></span>
<span class="line"><span>│      │ 重新执行 ui 阶段                                       │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  4   │ 修改产物后重新运行                                     │</span></span>
<span class="line"><span>│      │ 修改 artifacts/prd/prd.md 后重新执行                   │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  5   │ 暂停流水线                                             │</span></span>
<span class="line"><span>│      │ 保存当前进度，稍后继续                                 │</span></span>
<span class="line"><span>└──────┴──────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💡 提示：输入 1-5 之间的数字，然后按回车键确认您的选择</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>选项 2 被标记为&quot;⭐ 推荐选项，节省 Token&quot;</li></ul><p>在当前会话中，我们可以选择选项 5（暂停流水线），然后在新的命令行窗口中执行 <code>factory continue</code>。</p><p><strong>为什么</strong></p><ul><li>选项 1 是&quot;继续下一阶段（同一会话）&quot;，这会在当前会话中继续，上下文会累积</li><li>选项 2 是&quot;新建会话继续&quot;，这会用新的干净上下文执行下一阶段，<strong>节省 Token</strong></li><li>选项 5 是&quot;暂停流水线&quot;，这会保存当前进度，之后可以用 <code>factory continue</code> 恢复</li></ul><h3 id="第-2-步-在新命令行窗口执行-factory-continue" tabindex="-1">第 2 步：在新命令行窗口执行 <code>factory continue</code> <a class="header-anchor" href="#第-2-步-在新命令行窗口执行-factory-continue" aria-label="Permalink to &quot;第 2 步：在新命令行窗口执行 \`factory continue\`&quot;">​</a></h3><p>打开一个新的终端窗口（或标签页），进入你的项目目录，然后执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent Factory - Continue in New Session</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pipeline Status:</span></span>
<span class="line"><span>────────────────────────────────────────</span></span>
<span class="line"><span>Project: my-awesome-app</span></span>
<span class="line"><span>Status: Waiting</span></span>
<span class="line"><span>Current Stage: tech</span></span>
<span class="line"><span>Completed: bootstrap, prd</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Starting new Claude Code session...</span></span>
<span class="line"><span>✓ 新 Claude Code 窗口已启动</span></span>
<span class="line"><span>  (Please wait for the window to open)</span></span></code></pre></div><p><strong>发生了什么</strong>：</p><ol><li><code>factory continue</code> 命令读取了 <code>.factory/state.json</code>，知道当前状态</li><li>显示了当前项目的状态信息</li><li>自动启动了新的 Claude Code 窗口，并传递了&quot;请继续执行流水线&quot;的指令</li><li>新窗口会自动从 <code>tech</code> 阶段继续执行</li></ol><h3 id="第-3-步-在新窗口中继续执行" tabindex="-1">第 3 步：在新窗口中继续执行 <a class="header-anchor" href="#第-3-步-在新窗口中继续执行" aria-label="Permalink to &quot;第 3 步：在新窗口中继续执行&quot;">​</a></h3><p>新的 Claude Code 窗口启动后，你会看到一个新的对话，但是状态是从之前保存的检查点恢复的。</p><p>在新的会话中，Agent 会：</p><ol><li>读取 <code>.factory/state.json</code> 获取当前阶段</li><li>读取 <code>.factory/pipeline.yaml</code> 确定该阶段的输入和输出</li><li><strong>仅加载该阶段所需的输入文件</strong>（例如 <code>artifacts/prd/prd.md</code>）</li><li>执行该阶段的任务</li></ol><p><strong>关键点</strong>：</p><ul><li>新会话中没有之前阶段的对话历史</li><li>Agent 只从输入文件读取信息，不依赖&quot;记忆&quot;</li><li>这就是<strong>上下文隔离</strong>的体现</li></ul><h3 id="第-4-步-验证上下文隔离" tabindex="-1">第 4 步：验证上下文隔离 <a class="header-anchor" href="#第-4-步-验证上下文隔离" aria-label="Permalink to &quot;第 4 步：验证上下文隔离&quot;">​</a></h3><p>为了验证上下文隔离是否生效，你可以尝试在新会话中询问 Agent：</p><p>&quot;你知道 bootstrap 阶段做了什么吗？&quot;</p><p>如果上下文隔离生效，Agent 会说类似这样的话：</p><p>&quot;我需要先查看相关文件来了解之前的工作。让我读取一下...&quot;</p><p>然后它会尝试读取 <code>input/idea.md</code> 或其他文件来获取信息，而不是直接从对话历史中&quot;回忆&quot;。</p><p><strong>检查点 ✅</strong></p><ul><li>新会话启动成功</li><li>显示了正确的项目状态</li><li>Agent 只依赖输入文件，不依赖对话历史</li></ul><h3 id="第-5-步-继续执行剩余阶段" tabindex="-1">第 5 步：继续执行剩余阶段 <a class="header-anchor" href="#第-5-步-继续执行剩余阶段" aria-label="Permalink to &quot;第 5 步：继续执行剩余阶段&quot;">​</a></h3><p>每个阶段完成后，你都可以选择：</p><ul><li>在当前会话中继续（选项 1）- 适用于短流程</li><li><strong>新建会话继续（选项 2）</strong> - <strong>推荐，节省 Token</strong></li><li>暂停流水线（选项 5）- 之后再执行 <code>factory continue</code></li></ul><p>对于完整的 7 阶段流水线，建议每个阶段都使用&quot;新建会话继续&quot;，这样：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bootstrap (会话 1) → prd (会话 2) → ui (会话 3) → tech (会话 4)</span></span>
<span class="line"><span>→ code (会话 5) → validation (会话 6) → preview (会话 7)</span></span></code></pre></div><p>每个会话都是干净的，不需要加载之前所有阶段的内容。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="坑-1-忘记执行-factory-continue" tabindex="-1">坑 1：忘记执行 <code>factory continue</code> <a class="header-anchor" href="#坑-1-忘记执行-factory-continue" aria-label="Permalink to &quot;坑 1：忘记执行 \`factory continue\`&quot;">​</a></h3><p><strong>错误做法</strong>：</p><ul><li>在旧会话中直接开始下一阶段</li><li>或者在新窗口中直接打开 Claude Code 而不执行 <code>factory continue</code></li></ul><p><strong>正确做法</strong>：</p><ul><li>总是使用 <code>factory continue</code> 命令启动新会话</li><li>该命令会自动读取状态并传递正确的指令</li></ul><h3 id="坑-2-在新会话中重复加载历史文件" tabindex="-1">坑 2：在新会话中重复加载历史文件 <a class="header-anchor" href="#坑-2-在新会话中重复加载历史文件" aria-label="Permalink to &quot;坑 2：在新会话中重复加载历史文件&quot;">​</a></h3><p><strong>错误做法</strong>：</p><ul><li>在新会话中手动要求 AI 读取之前阶段的产物</li><li>认为 AI 应该&quot;知道&quot;之前发生了什么</li></ul><p><strong>正确做法</strong>：</p><ul><li>相信上下文隔离机制，Agent 会自动从输入文件读取信息</li><li>只提供该阶段需要的输入文件</li></ul><h3 id="坑-3-跨项目使用-factory-continue" tabindex="-1">坑 3：跨项目使用 <code>factory continue</code> <a class="header-anchor" href="#坑-3-跨项目使用-factory-continue" aria-label="Permalink to &quot;坑 3：跨项目使用 \`factory continue\`&quot;">​</a></h3><p><strong>错误做法</strong>：</p><ul><li>在项目 A 中执行 <code>factory continue</code>，但当前目录是项目 B</li></ul><p><strong>正确做法</strong>：</p><ul><li><code>factory continue</code> 会检查当前目录是否为 Factory 项目</li><li>如果不是，会提示需要先执行 <code>factory init</code></li></ul><h3 id="坑-4-修改产物后未使用-factory-continue" tabindex="-1">坑 4：修改产物后未使用 <code>factory continue</code> <a class="header-anchor" href="#坑-4-修改产物后未使用-factory-continue" aria-label="Permalink to &quot;坑 4：修改产物后未使用 \`factory continue\`&quot;">​</a></h3><p><strong>场景</strong>：</p><ul><li>你在某个阶段完成后，手动修改了产物（如修改了 PRD）</li><li>想继续执行下一阶段</li></ul><p><strong>正确做法</strong>：</p><ul><li>执行 <code>factory run</code>（会从指定阶段重新开始）</li><li>或者执行 <code>factory continue</code>（会从当前检查点继续）</li><li>不要直接在旧会话中继续，因为上下文可能不一致</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>本课学习了如何使用 <code>factory continue</code> 命令进行分会话执行：</p><h3 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h3><ol><li><strong>分会话执行</strong>：每个阶段完成后，用新会话执行下一阶段</li><li><strong>上下文隔离</strong>：Agent 只依赖输入文件，不依赖对话历史</li><li><strong>状态恢复</strong>：<code>.factory/state.json</code> 记录当前进度，新会话可以恢复</li><li><strong>节省 Token</strong>：避免加载过长的上下文，大幅降低成本</li></ol><h3 id="命令速查" tabindex="-1">命令速查 <a class="header-anchor" href="#命令速查" aria-label="Permalink to &quot;命令速查&quot;">​</a></h3><table tabindex="0"><thead><tr><th>命令</th><th>作用</th><th>使用场景</th></tr></thead><tbody><tr><td><code>factory continue</code></td><td>新建会话继续执行流水线</td><td>每个阶段完成后</td></tr><tr><td><code>factory run</code></td><td>在当前会话中运行流水线</td><td>首次运行或调试</td></tr><tr><td><code>factory status</code></td><td>查看当前项目状态</td><td>了解进度</td></tr></tbody></table><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h3><ul><li>✅ 完整执行 7 阶段流水线时，每个阶段都使用 <code>factory continue</code></li><li>✅ 在检查点选择&quot;新建会话继续&quot;（选项 2）</li><li>✅ 相信上下文隔离机制，不要手动加载历史文件</li><li>✅ 使用 <code>factory status</code> 检查项目进度</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../security-permissions/">权限与安全机制</a></strong>。</p><p>你会学到：</p><ul><li>能力边界矩阵如何防止 Agent 越权</li><li>越权处理机制和不可信产物隔离</li><li>安全检查点和权限校验流程</li><li>如何配置 Claude Code 的权限文件</li></ul></blockquote><p>这节课将帮助你理解 Agent App Factory 的安全机制，确保每个 Agent 只在授权目录中读写文件。</p><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>factory continue 命令</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-144</td></tr><tr><td>调度器上下文优化</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>113-154</td></tr><tr><td>上下文隔离策略</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>1-64</td></tr></tbody></table><p><strong>关键函数</strong>：</p><ul><li><code>launchClaudeCode(projectDir, nextStage, completedStages)</code>：启动新的 Claude Code 窗口</li><li><code>commandExists(cmd)</code>：检查命令是否可用</li><li><code>module.exports(projectDir)</code>：<code>factory continue</code> 命令的主函数</li></ul><p><strong>关键常量</strong>：</p><ul><li><code>state.json</code>：状态文件路径（<code>.factory/state.json</code>）</li><li><code>pipeline.yaml</code>：流水线定义文件路径（<code>.factory/pipeline.yaml</code>）</li><li><code>config.yaml</code>：项目配置文件路径（<code>.factory/config.yaml</code>）</li></ul><p><strong>关键业务规则</strong>：</p><ul><li>BR-6-1：每阶段独享干净上下文</li><li>BR-6-2：使用 <code>factory continue</code> 命令继续</li><li>BR-6-3：仅加载当前阶段所需文件</li></ul></details>`,104)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
